// Inspired by:
//   - Linear (darkmodedesign.com): deep-black ambient product previews, rounded grotesque at scale
//   - Obsidian (darkmodedesign.com): violet accent on #1a1a1a, knowledge-graph metaphor
//   - 108 Supply (darkmodedesign.com): editorial sparse type, counted items ("027 templates")
//   - minimal.gallery / KOMETA: bold type as primary design element
// Theme: DARK — near-black with violet+teal, focused "reading mode" aesthetic
// Generated by RAM Design Heartbeat — 2026-03-28

const fs = require('fs');

const W = 390, H = 844;
const PAD = 24;

const C = {
  bg:        '#0C0C10',
  surface:   '#131318',
  surface2:  '#1C1C26',
  border:    '#252532',
  text:      '#E8E4F0',
  muted:     'rgba(200,192,228,0.45)',
  dim:       'rgba(200,192,228,0.14)',
  accent:    '#7B5EA7',
  accentBr:  '#9B7EC8',
  teal:      '#3ECFCF',
  tealDim:   'rgba(62,207,207,0.14)',
  violetDim: 'rgba(123,94,167,0.18)',
  violetMid: 'rgba(123,94,167,0.40)',
  red:       '#E05C5C',
  amber:     '#E8A040',
  green:     '#4EC994',
};

function rect(x, y, w, h, fill, opts = {}) {
  return { type: 'RECTANGLE', x, y, width: Math.max(w, 0.5), height: Math.max(h, 0.5), fill, cornerRadius: opts.r || 0, opacity: opts.opacity || 1, stroke: opts.stroke || null, strokeWidth: opts.sw || 0 };
}

function text(content, x, y, opts = {}) {
  return {
    type: 'TEXT', x, y, content,
    fontSize: opts.size || 14,
    fontFamily: opts.font || 'Inter',
    fontWeight: opts.weight || '400',
    fill: opts.color || C.text,
    letterSpacing: opts.ls !== undefined ? opts.ls : -0.2,
    lineHeight: opts.lh || 1.35,
    width: opts.w || 300,
    align: opts.align || 'left',
    opacity: opts.opacity || 1,
  };
}

function line(x1, y1, x2, y2, color, opts = {}) {
  return { type: 'LINE', x: x1, y: y1, points: [{ x: 0, y: 0 }, { x: x2 - x1, y: y2 - y1 }], stroke: color, strokeWidth: opts.sw || 1, opacity: opts.opacity || 1 };
}

function pill(label, x, y, fill, textColor, opts = {}) {
  const w = opts.w || Math.max(label.length * 6.5 + 18, 32);
  const h = opts.h || 22;
  return {
    type: 'GROUP', x, y,
    children: [
      rect(0, 0, w, h, fill, { r: h / 2 }),
      text(label, 9, (h - 13) / 2 + 1, { size: 10, weight: '600', color: textColor, ls: 0.2, w: w - 18 }),
    ],
  };
}

function statusBar() {
  return {
    type: 'GROUP', x: 0, y: 0,
    children: [
      rect(0, 0, W, 48, C.bg),
      text('9:41', PAD, 16, { size: 15, weight: '600', color: C.text, ls: 0, w: 60 }),
      text('●●  ▲  ▌▌', W - PAD - 72, 16, { size: 11, weight: '500', color: C.muted, ls: 0.8, w: 72, align: 'right' }),
    ],
  };
}

function navBar(active) {
  const tabs = [
    { label: 'Home',   icon: '⌂', x: 0   },
    { label: 'Read',   icon: '◫', x: 78  },
    { label: 'Notes',  icon: '◈', x: 156 },
    { label: 'Graph',  icon: '◎', x: 243 },
    { label: 'Review', icon: '↻', x: 321 },
  ];
  const items = [rect(0, 0, W, 72, C.surface), line(0, 0, W, 0, C.border, { sw: 1 })];
  tabs.forEach((tab, i) => {
    const isActive = i === active;
    items.push(
      text(tab.icon, tab.x + 24, 12, { size: 17, color: isActive ? C.accentBr : C.muted, w: 30, align: 'center' }),
      text(tab.label, tab.x + 6, 36, { size: 9, weight: isActive ? '700' : '400', color: isActive ? C.accentBr : C.muted, ls: 0.3, w: 66, align: 'center' }),
    );
    if (isActive) items.push(rect(tab.x + 22, 58, 35, 2, C.accentBr, { r: 1 }));
  });
  return { type: 'GROUP', x: 0, y: H - 72, children: items };
}

function card(x, y, w, h, children, opts = {}) {
  return {
    type: 'GROUP', x, y,
    children: [
      rect(0, 0, w, h, C.surface, { r: opts.r || 12, stroke: C.border, sw: 1 }),
      ...children,
    ],
  };
}

function accentCard(x, y, w, h, accentColor, children, opts = {}) {
  return {
    type: 'GROUP', x, y,
    children: [
      rect(0, 0, w, h, C.surface, { r: opts.r || 12, stroke: accentColor, sw: 1 }),
      rect(0, 0, 3, h, accentColor, { r: 2 }),
      ...children,
    ],
  };
}

