// ── SCREEN 4: KNOWLEDGE GRAPH ────────────────────────────────────

function screen4() {
  const els = [];
  els.push(rect(0, 0, W, H, '#080810'));
  els.push(statusBar());

  els.push(text('Knowledge Graph', PAD, 60, { size: 22, weight: '700', color: C.text, ls: -0.8, w: 260 }));
  els.push(text('14 concepts · 27 links', PAD, 88, { size: 12, color: C.muted, ls: -0.1, w: 200 }));

  const GX = PAD, GY = 108, GW = W - PAD * 2, GH = 460;
  els.push(rect(GX, GY, GW, GH, '#0B0B14', { r: 16, stroke: C.border, sw: 1 }));

  // Ambient dot grid
  for (let gx = GX + 14; gx < GX + GW - 8; gx += 26) {
    for (let gy = GY + 14; gy < GY + GH - 8; gy += 26) {
      els.push(rect(gx, gy, 2, 2, C.dim, { r: 1 }));
    }
  }

  const nodes = [
    { id: 'epistemology', x: 195, y: 220, r: 22, color: C.accent,   label: 'Epistemology' },
    { id: 'llm',          x: 108, y: 300, r: 16, color: C.teal,     label: 'LLMs'         },
    { id: 'wonder',       x: 286, y: 280, r: 14, color: C.accentBr, label: 'Wonder'       },
    { id: 'maps',         x: 148, y: 388, r: 13, color: C.amber,    label: 'Models'       },
    { id: 'memory',       x: 302, y: 384, r: 12, color: C.green,    label: 'Memory'       },
    { id: 'rnn',          x: 76,  y: 418, r: 10, color: C.teal,     label: 'RNNs'         },
    { id: 'goodhart',     x: 244, y: 188, r: 10, color: C.amber,    label: "Goodhart's"   },
    { id: 'attention',    x: 334, y: 162, r: 10, color: C.green,    label: 'Attention'    },
  ];

  const edges = [
    ['epistemology','llm'],['epistemology','wonder'],['epistemology','maps'],
    ['llm','rnn'],['llm','maps'],['wonder','memory'],['wonder','attention'],
    ['maps','goodhart'],['memory','rnn'],['goodhart','epistemology'],['attention','llm'],
  ];

  const nodeMap = Object.fromEntries(nodes.map(n => [n.id, n]));
  edges.forEach(([a, b]) => {
    const na = nodeMap[a], nb = nodeMap[b];
    if (!na || !nb) return;
    const isTeal = (a === 'llm' || b === 'llm' || a === 'rnn' || b === 'rnn');
    els.push(line(GX + na.x, GY + na.y, GX + nb.x, GY + nb.y, isTeal ? 'rgba(62,207,207,0.22)' : 'rgba(123,94,167,0.22)', { sw: 1 }));
  });

  nodes.forEach(n => {
    const isSel = n.id === 'epistemology';
    // Glow
    const glowFill = n.color + '1F'; // ~12% alpha
    els.push(rect(GX + n.x - n.r * 2, GY + n.y - n.r * 2, n.r * 4, n.r * 4, glowFill, { r: n.r * 2 }));
    // Circle
    els.push(rect(GX + n.x - n.r, GY + n.y - n.r, n.r * 2, n.r * 2, isSel ? n.color : C.surface2, { r: n.r, stroke: n.color, sw: isSel ? 2 : 1 }));
    // Label
    els.push(text(n.label, GX + n.x - 44, GY + n.y + n.r + 5, { size: 9, weight: isSel ? '700' : '400', color: isSel ? n.color : C.muted, ls: 0.1, w: 88, align: 'center' }));
  });

  // Selected node detail
  els.push(
    card(PAD, GY + GH + 8, W - PAD * 2, 80, [
      rect(0, 0, 3, 80, C.accent, { r: 2 }),
      text('Epistemology', 14, 12, { size: 14, weight: '700', color: C.text, ls: -0.3, w: 180 }),
      text('8 highlights · 5 connections · 3 orphaned', 14, 34, { size: 11, color: C.muted, ls: 0, w: W - PAD * 2 - 90 }),
      text('Tap to explore →', 14, 56, { size: 11, weight: '500', color: C.accentBr, ls: 0, w: 140 }),
      rect(W - PAD * 2 - 46, 12, 42, 42, C.violetDim, { r: 21 }),
      text('8', W - PAD * 2 - 27, 24, { size: 16, weight: '700', color: C.accentBr, ls: -0.5, w: 14, align: 'center' }),
    ]),
  );

  els.push(navBar(3));
  return { name: 'Graph — Knowledge Map', width: W, height: H, elements: els };
}

